Properties that work both in Python/Rust AND in SQL queries.

## Python Behavior

```python
from sqlalchemy.ext.hybrid import hybrid_property

class User(SQLModel, table=True):
    first_name: str
    last_name: str

    @hybrid_property
    def full_name(self):
        return self.first_name + ' ' + self.last_name

    @full_name.expression
    def full_name(cls):
        return cls.first_name + ' ' + cls.last_name

# Works in Rust:
print(user.full_name)

# Works in SQL:
session.exec(select(User).where(User.full_name == 'John Doe'))
# Generates: WHERE first_name || ' ' || last_name = 'John Doe'
```

## Rust Implementation

```rust
#[derive(Model)]
struct User {
    first_name: String,
    last_name: String,
}

impl User {
    // Rust-side computation
    pub fn full_name(&self) -> String {
        format\!("{} {}", self.first_name, self.last_name)
    }
}

// SQL expression for query
impl User {
    pub fn full_name_expr() -> Expr {
        Expr::col("first_name")
            .concat(" ")
            .concat(Expr::col("last_name"))
    }
}

// Usage in query
select\!(User)
    .filter(User::full_name_expr().eq("John Doe"))
```

